import React, { useState, useEffect } from "react";
import TopNavBar from "../components/TopNavBar";
import Header from "../components/Header";
import { api } from "../api";
import { useNavigate } from "react-router-dom";

export default function Homepage() {
  const [dashboard, setDashboard] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const token = localStorage.getItem("token");
        if (!token) {
          setDashboard({ error: "You are not logged in. Please login again." });
          setLoading(false);
          return;
        }
        const res = await api.get("/dashboard", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setDashboard(res.data);
      } catch (err) {
        setDashboard({ error: "Failed to fetch dashboard data." });
      } finally {
        setLoading(false);
      }
    };
    fetchDashboard();
  }, []);

  if (loading) return <div>Loading...</div>;
  if (dashboard?.error) return <div>{dashboard.error}</div>;

  // ...rest of your rendering code below (UI unchanged)
  // You can keep your existing UI here from before
}
